const DEFAULT_TYPES = ['application/json', 'text/plain'];

export function parseCompressibleTypes(rawValue) {
  if (rawValue === undefined) {
    return [...DEFAULT_TYPES];
  }
  if (typeof rawValue !== 'string') {
    throw new TypeError('COMPRESS_TYPES must be a string');
  }

  return rawValue.split(',').map((value) => value.toLowerCase());
}

