import { parseCompressibleTypes } from './compression-config.mjs';
import { matchesConfiguredType } from './content-type-match.mjs';

export function createCompressionDecider(environment = {}) {
  const configuredTypes = parseCompressibleTypes(environment.COMPRESS_TYPES);
  return (contentType) => matchesConfiguredType(contentType, configuredTypes);
}

