import test from 'node:test';
import assert from 'node:assert/strict';

import { parseCompressibleTypes } from '../src/compression-config.mjs';
import { matchesConfiguredType } from '../src/content-type-match.mjs';
import { createCompressionDecider } from '../src/compress-response.mjs';

test('default compressible types are available when configuration is absent', () => {
  assert.deepEqual(parseCompressibleTypes(undefined), [
    'application/json',
    'text/plain'
  ]);
});

test('an exact configured media type matches case-insensitively', () => {
  assert.equal(
    matchesConfiguredType('Application/JSON', ['application/json']),
    true
  );
  assert.equal(matchesConfiguredType('image/png', ['application/json']), false);
});

test('the compression decider uses the deployment configuration', () => {
  const shouldCompress = createCompressionDecider({
    COMPRESS_TYPES: 'application/json,text/csv'
  });

  assert.equal(shouldCompress('application/json'), true);
  assert.equal(shouldCompress('text/csv'), true);
  assert.equal(shouldCompress('application/zip'), false);
});
